+/// Execute a SQL query on a table using DataFrame API
+fn executeQuery(allocator: std.mem.Allocator, table: *Table, sql_str: []const u8) !ResultSet {
+    _ = sql_str; // TODO: Parse and execute SQL when lanceql parser is ready
+
+    // Create DataFrame from table
+    var df = DataFrame.from(allocator, table);
+
+    // For now, just collect all data
+    // TODO: Add SQL parsing when lanceql.query.Parser.parseExpr() is made public
+    // Will support: WHERE, ORDER BY, LIMIT, GROUP BY, etc.
+
+    // Execute and collect results
+    return try df.collect();
+}
