+/// Format a ResultSet as markdown table for LLM context
+fn formatResultSet(allocator: std.mem.Allocator, result: ResultSet, max_rows: u32) ![]u8 {
+    var output: std.ArrayListUnmanaged(u8) = .empty;
+
+    const row_count = result.rowCount();
+    const col_count = result.columnCount();
+
+    if (col_count == 0) {
+        try output.appendSlice(allocator, "No columns in result\n");
+        return try output.toOwnedSlice(allocator);
+    }
+
+    // Add row count
+    var count_buf: [64]u8 = undefined;
+    const showing = @min(row_count, max_rows);
+    const count_str = if (row_count > max_rows)
+        try std.fmt.bufPrint(&count_buf, "Rows: {} (showing first {})\n\n", .{row_count, showing})
+    else
+        try std.fmt.bufPrint(&count_buf, "Rows: {}\n\n", .{row_count});
+    try output.appendSlice(allocator, count_str);
+
+    if (row_count == 0) {
+        try output.appendSlice(allocator, "(empty result)\n");
+        return try output.toOwnedSlice(allocator);
+    }
+
+    // Build header
+    try output.appendSlice(allocator, "| ");
+    for (result.columns, 0..) |col_name, i| {
+        try output.appendSlice(allocator, col_name);
+        try output.appendSlice(allocator, " |");
+        if (i < col_count - 1) try output.appendSlice(allocator, " ");
+    }
+    try output.appendSlice(allocator, "\n");
+
+    // Add separator
+    try output.appendSlice(allocator, "|");
+    for (0..col_count) |_| {
+        try output.appendSlice(allocator, "--------|");
+    }
+    try output.appendSlice(allocator, "\n");
+
+    // Add rows (up to max_rows)
+    const limit = @min(row_count, showing);
+    for (result.rows[0..limit]) |row| {
+        try output.appendSlice(allocator, "| ");
+        for (row, 0..) |val, i| {
+            const val_str = try formatValue(allocator, val);
+            defer allocator.free(val_str);
+            try output.appendSlice(allocator, val_str);
+            try output.appendSlice(allocator, " |");
+            if (i < col_count - 1) try output.appendSlice(allocator, " ");
+        }
+        try output.appendSlice(allocator, "\n");
+    }
+
+    // Add truncation notice if needed
+    if (row_count > max_rows) {
+        var notice_buf: [128]u8 = undefined;
+        const notice = try std.fmt.bufPrint(&notice_buf, "\n(Results truncated. Use LIMIT clause or increase max_results)\n", .{});
+        try output.appendSlice(allocator, notice);
+    }
+
+    return try output.toOwnedSlice(allocator);
+}
+
+/// Format a single Value for display
+fn formatValue(allocator: std.mem.Allocator, value: Value) ![]u8 {
+    return switch (value) {
+        .null => try allocator.dupe(u8, "NULL"),
+        .int64 => |v| try std.fmt.allocPrint(allocator, "{}", .{v}),
+        .float64 => |v| try std.fmt.allocPrint(allocator, "{d:.4}", .{v}),
+        .bool_ => |v| try allocator.dupe(u8, if (v) "true" else "false"),
+        .string => |v| try std.fmt.allocPrint(allocator, "\"{s}\"", .{v}),
+    };
+}
